import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { toast } from 'sonner';

export default function Register() {
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await new Promise(r => setTimeout(r, 1000));
      // const res = await fetch('http://localhost:8000/api/auth/register', {
      //   method: 'POST',
      //   headers: { 'Content-Type': 'application/json' },
      //   body: JSON.stringify({
      //       email: formData.email,
      //       password: formData.password,
      //       first_name: formData.firstName,
      //       last_name: formData.lastName
      //   })
      // });
      // if (!res.ok) throw new Error('Registration failed');
      toast.success('Account created successfully!');
      navigate('/login');
    } catch (err) {
      toast.error(err.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-[80vh] items-center justify-center py-12 px-4 sm:px-6 lg:px-8 bg-background">
      <div className="w-full max-w-md space-y-8 bg-card p-10 rounded-2xl shadow-xl border border-border/50">
        <div>
          <h2 className="mt-6 text-center text-3xl font-bold tracking-tight font-serif text-foreground">
            Create an account
          </h2>
          <p className="mt-2 text-center text-sm text-muted-foreground">
            Or{' '}
            <Link to="/login" className="font-medium text-primary hover:text-primary/80 transition-colors">
              sign in to your account
            </Link>
          </p>
        </div>
        <form className="mt-8 space-y-6" onSubmit={handleRegister}>
          <div className="space-y-4 rounded-md shadow-sm">
            <div className="grid grid-cols-2 gap-4">
               <div>
                <label className="sr-only" htmlFor="firstName">First Name</label>
                <input
                  id="firstName" name="firstName" type="text" required
                  className="relative block w-full rounded-md border border-input bg-background px-3 py-3 text-foreground placeholder:text-muted-foreground focus:z-10 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary sm:text-sm transition-all"
                  placeholder="First name"
                  value={formData.firstName} onChange={handleChange}
                />
              </div>
              <div>
                <label className="sr-only" htmlFor="lastName">Last Name</label>
                <input
                  id="lastName" name="lastName" type="text" required
                  className="relative block w-full rounded-md border border-input bg-background px-3 py-3 text-foreground placeholder:text-muted-foreground focus:z-10 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary sm:text-sm transition-all"
                  placeholder="Last name"
                  value={formData.lastName} onChange={handleChange}
                />
              </div>
            </div>
            
            <div>
              <label className="sr-only" htmlFor="email-address">Email address</label>
              <input
                id="email-address" name="email" type="email" autoComplete="email" required
                className="relative block w-full rounded-md border border-input bg-background px-3 py-3 text-foreground placeholder:text-muted-foreground focus:z-10 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary sm:text-sm transition-all"
                placeholder="Email address"
                value={formData.email} onChange={handleChange}
              />
            </div>
            <div>
              <label className="sr-only" htmlFor="password">Password</label>
              <input
                id="password" name="password" type="password" autoComplete="new-password" required
                className="relative block w-full rounded-md border border-input bg-background px-3 py-3 text-foreground placeholder:text-muted-foreground focus:z-10 focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary sm:text-sm transition-all"
                placeholder="Password"
                value={formData.password} onChange={handleChange}
              />
            </div>
          </div>

          <div>
            <button
              type="submit"
              disabled={loading}
              className="group relative flex w-full justify-center rounded-md bg-primary px-3 py-3 text-sm font-semibold text-primary-foreground hover:bg-primary/90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-primary transition-all disabled:opacity-70 disabled:cursor-not-allowed"
            >
              {loading ? 'Creating...' : 'Create Account'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
